static int toJavaVersionInt(String version) {
    if (version == null || version.isEmpty()) {
        return 0;
    }
    String[] versionParts = version.split("\\.");
    int major = versionParts.length > 0 ? parseVersionPart(versionParts[0]) * 100 : 0;
    int minor = versionParts.length > 1 ? parseVersionPart(versionParts[1]) * 10 : 0;
    int patch = versionParts.length > 2 ? parseVersionPart(versionParts[2]) : 0;
    return major + minor + patch;
}

private static int parseVersionPart(String part) {
    try {
        // Extract numeric part only
        String numericPart = part.replaceAll("\\D", "");
        return Integer.parseInt(numericPart);
    } catch (NumberFormatException e) {
        return 0;
    }
}

static int toJavaVersionInt(String version) {
    if (version == null || version.trim().isEmpty()) {
        return 0;
    }
    try {
        return toVersionInt(toJavaVersionIntArray(version, JAVA_VERSION_TRIM_SIZE));
    } catch (Exception e) {
        return 0;
    }
}
